# src/services/genai/interface.py — the contract all adapters implement
from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import AsyncIterator

@dataclass
class ChatMessage:
    role: str    # "user" | "assistant" | "system"
    content: str

@dataclass
class ChatResult:
    content: str
    model: str
    input_tokens: int
    output_tokens: int
    finish_reason: str   # "end_turn" | "max_tokens" | "stop_sequence"

@dataclass
class EmbedResult:
    embedding: list[float]
    model: str
    input_tokens: int

class LLMClient(ABC):
    @abstractmethod
    async def chat(
        self,
        messages: list[ChatMessage],
        *,
        max_tokens: int = 1024,
        temperature: float = 1.0,
        system: str | None = None,
    ) -> ChatResult: ...

    @abstractmethod
    async def embed(self, text: str) -> EmbedResult: ...

    @abstractmethod
    async def stream_chat(
        self,
        messages: list[ChatMessage],
        *,
        max_tokens: int = 1024,
        system: str | None = None,
    ) -> AsyncIterator[str]: ...

# src/services/genai/errors.py
from dataclasses import dataclass

class GenAIError(Exception):
    pass

@dataclass
class ProviderError(GenAIError):
    provider: str
    status: int         # HTTP status code
    message: str

    def is_retryable(self) -> bool:
        return self.status in (429, 500, 502, 503, 529)

    def is_quota_exceeded(self) -> bool:
        return self.status == 429

@dataclass
class ProviderConnectionError(GenAIError):
    provider: str   # always retryable

@dataclass
class ContextWindowExceeded(GenAIError):
    provider: str
    max_tokens: int
    actual_tokens: int

@dataclass
class ContentPolicyViolation(GenAIError):
    provider: str
    reason: str   # never retry; surface to caller

